#include <iostream>
#include <string>

class Solution {
public:
    int minSwapsToMakeUniqueAndPalindromic(std::string s) {
        int n = s.length();
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (s.substr(i, j - i + 1) != s.substr(j, j - i + 1)) {
                    count++;
                }
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (s.substr(i, j - i + 1) == s.substr(j, j - i + 1) && s.substr(i, j - i + 1).length() > 1) {
                    count += s.substr(i, j - i + 1).length() - 1;
                }
            }
        }
        return count;
    }
};

int main() {
    Solution s;
    std::string s1 = "abaac";
    std::cout << s.minSwapsToMakeUniqueAndPalindromic(s1) << std::endl;
    return 0;
}
